1	package agent
2	
3	import (
4		"strings"
5	
6		"github.com/DocumentDrivenDX/ddx/internal/config"
7		"github.com/DocumentDrivenDX/ddx/internal/escalation"
8	)
9	
10	const DefaultRoutingProfile = "default"
11	
12	var profileTierRank = map[string]int{
13		"cheap":    0,
14		"fast":     1,
15		"standard": 2,
16		"smart":    3,
17	}
18	
19	// ResolveProfileLadder returns the ordered tiers to try for profile after
20	// applying explicit --min-tier / --max-tier caps.
21	func ResolveProfileLadder(routing *config.RoutingConfig, profile, minTier, maxTier string) []escalation.ModelTier {
22		profile = NormalizeRoutingProfile(profile)
23		ladder := routing.ResolvedLadder(profile)
24		out := make([]escalation.ModelTier, 0, len(ladder))
25		for _, raw := range ladder {
26			tier := strings.TrimSpace(raw)
27			if tier == "" || !tierWithinBounds(tier, minTier, maxTier) {
28				continue
29			}
30			out = append(out, escalation.ModelTier(tier))
31		}
32		return out
33	}
34	
35	func NormalizeRoutingProfile(profile string) string {
36		profile = strings.TrimSpace(profile)
37		if profile == "" {
38			return DefaultRoutingProfile
39		}
40		return profile
41	}
42	
43	// ResolveTierModelRef applies agent.routing.model_overrides for a ladder tier.
44	func ResolveTierModelRef(routing *config.RoutingConfig, tier escalation.ModelTier) string {
45		tierRef := string(tier)
46		if routing != nil && routing.ModelOverrides != nil {
47			if override := strings.TrimSpace(routing.ModelOverrides[tierRef]); override != "" {
48				return override
49			}
50		}
51		return tierRef
52	}
53	
54	func tierWithinBounds(tier, minTier, maxTier string) bool {
55		rank, ok := profileTierRank[tier]
56		if !ok {
57			return minTier == "" && maxTier == ""
58		}
59		if minTier != "" {
60			if minRank, ok := profileTierRank[minTier]; ok && rank < minRank {
61				return false
62			}
63		}
64		if maxTier != "" {
65			if maxRank, ok := profileTierRank[maxTier]; ok && rank > maxRank {
66				return false
67			}
68		}
69		return true
70	}
