1	package server
2	
3	import (
4		"context"
5		"encoding/json"
6		"fmt"
7		"time"
8	
9		"github.com/DocumentDrivenDX/ddx/internal/config"
10		ddxexec "github.com/DocumentDrivenDX/ddx/internal/exec"
11		ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
12	)
13	
14	// execLogAdapter implements ddxgraphql.ExecLogProvider using the exec store.
15	type execLogAdapter struct {
16		workingDir string
17	}
18	
19	func (a *execLogAdapter) GetExecLog(runID string) (string, string, error) {
20		store := ddxexec.NewStore(a.workingDir)
21		return store.Log(runID)
22	}
23	
24	// coordMetricsAdapter implements ddxgraphql.CoordinatorMetricsProvider using
25	// the coordinator registry.
26	type coordMetricsAdapter struct {
27		reg *coordinatorRegistry
28	}
29	
30	func (a *coordMetricsAdapter) GetCoordinatorMetrics(projectRoot string) *ddxgraphql.CoordinatorMetricsSnap {
31		m := a.reg.MetricsFor(projectRoot)
32		if m == nil {
33			return nil
34		}
35		return &ddxgraphql.CoordinatorMetricsSnap{
36			Landed:          m.Landed,
37			Preserved:       m.Preserved,
38			Failed:          m.Failed,
39			PushFailed:      m.PushFailed,
40			TotalDurationMS: m.TotalDurationMS,
41			TotalCommits:    m.TotalCommits,
42		}
43	}
44	
45	// workerDispatchAdapter implements GraphQL action dispatch using the live
46	// WorkerManager.
47	type workerDispatchAdapter struct {
48		manager *WorkerManager
49	}
50	
51	func (a *workerDispatchAdapter) DispatchWorker(ctx context.Context, kind string, projectRoot string, rawArgs *string) (*ddxgraphql.WorkerDispatchResult, error) {
52		if a == nil || a.manager == nil {
53			return nil, fmt.Errorf("worker dispatcher is not configured")
54		}
55		if err := ctx.Err(); err != nil {
56			return nil, err
57		}
58		if kind != "execute-loop" {
59			return nil, fmt.Errorf("unsupported worker kind %q", kind)
60		}
61	
62		var req struct {
63			Harness       string `json:"harness"`
64			Model         string `json:"model"`
65			Profile       string `json:"profile"`
66			Provider      string `json:"provider"`
67			ModelRef      string `json:"model_ref"`
68			Effort        string `json:"effort"`
69			LabelFilter   string `json:"label_filter"`
70			Once          bool   `json:"once"`
71			PollInterval  string `json:"poll_interval"`
72			NoReview      bool   `json:"no_review"`
73			ReviewHarness string `json:"review_harness"`
74			ReviewModel   string `json:"review_model"`
75			MinTier       string `json:"min_tier"`
76			MaxTier       string `json:"max_tier"`
77		}
78		if rawArgs != nil && *rawArgs != "" {
79			if err := json.Unmarshal([]byte(*rawArgs), &req); err != nil {
80				return nil, fmt.Errorf("invalid worker args JSON: %w", err)
81			}
82		}
83	
84		// Apply .ddx/config.yaml workers.default_spec + enforce workers.max_count
85		// (ddx-b6cf025c). The max_count cap counts currently-running drain workers
86		// for this project so the "+ Add worker" button can refuse cleanly.
87		if wc := loadWorkersConfig(projectRoot); wc != nil {
88			if spec := wc.DefaultSpec; spec != nil {
89				if req.Harness == "" {
90					req.Harness = spec.Harness
91				}
92				if req.Profile == "" {
93					req.Profile = spec.Profile
94				}
95				if req.Effort == "" {
96					req.Effort = spec.Effort
97				}
98				if req.MinTier == "" {
99					req.MinTier = spec.MinTier
100				}
101				if req.MaxTier == "" {
102					req.MaxTier = spec.MaxTier
103				}
104			}
105			if wc.MaxCount != nil && *wc.MaxCount >= 0 {
106				running := a.countRunningDrainWorkers(projectRoot)
107				if running >= *wc.MaxCount {
108					return nil, fmt.Errorf("workers.max_count cap reached: %d running (limit %d)", running, *wc.MaxCount)
109				}
110			}
111		}
112	
113		var pollInterval time.Duration
114		if req.PollInterval != "" {
115			d, err := time.ParseDuration(req.PollInterval)
116			if err != nil {
117				return nil, fmt.Errorf("invalid poll_interval: %w", err)
118			}
119			pollInterval = d
120		}
121	
122		record, err := a.manager.StartExecuteLoop(ExecuteLoopWorkerSpec{
123			ProjectRoot:   projectRoot,
124			Harness:       req.Harness,
125			Model:         req.Model,
126			Profile:       req.Profile,
127			Provider:      req.Provider,
128			ModelRef:      req.ModelRef,
129			Effort:        req.Effort,
130			LabelFilter:   req.LabelFilter,
131			Once:          req.Once,
132			PollInterval:  pollInterval,
133			NoReview:      req.NoReview,
134			ReviewHarness: req.ReviewHarness,
135			ReviewModel:   req.ReviewModel,
136			MinTier:       req.MinTier,
137			MaxTier:       req.MaxTier,
138		})
139		if err != nil {
140			return nil, err
141		}
142		return &ddxgraphql.WorkerDispatchResult{
143			ID:    record.ID,
144			State: record.State,
145			Kind:  record.Kind,
146		}, nil
147	}
148	
149	// loadWorkersConfig reads .ddx/config.yaml at projectRoot and returns the
150	// workers block, or nil when unset / on error. Errors are swallowed because
151	// a missing or malformed config must not block the dispatch path.
152	func loadWorkersConfig(projectRoot string) *config.WorkersConfig {
153		if projectRoot == "" {
154			return nil
155		}
156		cfg, err := config.LoadWithWorkingDir(projectRoot)
157		if err != nil || cfg == nil {
158			return nil
159		}
160		return cfg.Workers
161	}
162	
163	// countRunningDrainWorkers counts execute-loop workers currently in state
164	// "running" for projectRoot. Returns 0 on any error.
165	func (a *workerDispatchAdapter) countRunningDrainWorkers(projectRoot string) int {
166		if a == nil || a.manager == nil {
167			return 0
168		}
169		recs, err := a.manager.List()
170		if err != nil {
171			return 0
172		}
173		count := 0
174		for _, rec := range recs {
175			if rec.Kind == "execute-loop" && rec.State == "running" && rec.ProjectRoot == projectRoot {
176				count++
177			}
178		}
179		return count
180	}
181	
182	func (a *workerDispatchAdapter) DispatchPlugin(ctx context.Context, projectRoot string, name string, action string, scope string) (*ddxgraphql.PluginDispatchResult, error) {
183		if a == nil || a.manager == nil {
184			return nil, fmt.Errorf("worker dispatcher is not configured")
185		}
186		if err := ctx.Err(); err != nil {
187			return nil, err
188		}
189		record, err := a.manager.StartPluginAction(PluginActionWorkerSpec{
190			ProjectRoot: projectRoot,
191			Name:        name,
192			Action:      action,
193			Scope:       scope,
194		}, func(runCtx context.Context) (string, error) {
195			if err := runCtx.Err(); err != nil {
196				return "", err
197			}
198			return ddxgraphql.DispatchPluginAction(projectRoot, name, action)
199		})
200		if err != nil {
201			return nil, err
202		}
203		return &ddxgraphql.PluginDispatchResult{
204			ID:     record.ID,
205			State:  record.State,
206			Action: action,
207		}, nil
208	}
209	
210	func (a *workerDispatchAdapter) StopWorker(ctx context.Context, id string) (*ddxgraphql.WorkerLifecycleResult, error) {
211		if a == nil || a.manager == nil {
212			return nil, fmt.Errorf("worker dispatcher is not configured")
213		}
214		if err := ctx.Err(); err != nil {
215			return nil, err
216		}
217		if err := a.manager.Stop(id); err != nil {
218			return nil, err
219		}
220		rec, err := a.manager.Show(id)
221		if err != nil {
222			return &ddxgraphql.WorkerLifecycleResult{ID: id, State: "stopping", Kind: "execute-loop"}, nil
223		}
224		return &ddxgraphql.WorkerLifecycleResult{
225			ID:    rec.ID,
226			State: rec.State,
227			Kind:  rec.Kind,
228		}, nil
229	}
