460	func (f *CommandFactory) newAgentCondenseCommand() *cobra.Command {
461		cmd := &cobra.Command{
462			Use:   "condense",
463			Short: "Filter raw agent output to progress-relevant lines",
464			Long: `Read raw agent output from stdin and write condensed output to stdout.
465	
466	Keeps: namespace-prefixed progress lines, tool calls, errors/warnings, issue IDs,
467	markdown structure (#, |, **), and phase markers. Drops raw diffs, codex
468	boilerplate (Commands run:, tokens used), and bulk verbose content.`,
469			RunE: func(cmd *cobra.Command, args []string) error {
470				namespace, _ := cmd.Flags().GetString("namespace")
471				data, err := io.ReadAll(os.Stdin)
472				if err != nil {
473					return fmt.Errorf("reading stdin: %w", err)
474				}
475				result := agent.CondenseOutput(string(data), namespace)
476				if result != "" {
477					fmt.Fprint(cmd.OutOrStdout(), result)
478					if !strings.HasSuffix(result, "\n") {
479						fmt.Fprintln(cmd.OutOrStdout())
480					}
481				}
482				return nil
483			},
484		}
485		cmd.Flags().String("namespace", "helix:", "Caller namespace prefix to keep (e.g. helix:)")
486		return cmd
487	}
