544	func profileModelOverrideForRun(workDir, profile string) string {
545		cfg, err := config.LoadWithWorkingDir(workDir)
546		if err != nil || cfg == nil || cfg.Agent == nil || cfg.Agent.Routing == nil {
547			return ""
548		}
549		tiers := agent.ResolveProfileLadder(cfg.Agent.Routing, profile, "", "")
550		if len(tiers) == 0 {
551			return ""
552		}
553		firstTier := tiers[0]
554		override := agent.ResolveTierModelRef(cfg.Agent.Routing, firstTier)
555		if override == string(firstTier) {
556			return ""
557		}
558		return override
559	}
